const $=id=>document.getElementById(id);
let site = JSON.parse(localStorage.getItem('rh_site_content')||'null') || DEFAULT_SITE;
let templates = JSON.parse(localStorage.getItem('rh_templates_data')||'null') || DEFAULT_TEMPLATES;
let airaQuestions = JSON.parse(localStorage.getItem('rh_aira_question_bank')||'null') || structuredClone(DEFAULT_AIRA_QUESTIONS);
let airaFaq = JSON.parse(localStorage.getItem('rh_aira_faq_bank')||'null') || structuredClone(DEFAULT_AIRA_FAQ);
let googleReviews = (window.RH_GOOGLE_REVIEWS_SERVICE&&window.RH_GOOGLE_REVIEWS_SERVICE.readLocal?window.RH_GOOGLE_REVIEWS_SERVICE.readLocal():{version:'1.0.0',title:'Apa Kata Customer Kami',subtitle:'Antara pengalaman pelanggan yang pernah berurusan dengan Restu Harmoni.',googleReviewUrl:'https://g.page/r/CTOjpXjmtEJwEAI/review',googleProfileUrl:'https://g.page/r/CTOjpXjmtEJwEAI',reviews:[]});

document.getElementById('logout').onclick=()=>window.RH_ADMIN_AUTH.signOut();

document.querySelectorAll('.side button[data-tab]').forEach(btn=>btn.onclick=()=>{
 document.querySelectorAll('.side button').forEach(b=>b.classList.remove('active')); btn.classList.add('active');
 ['dashboard','site','templates','blog','aira','reviews','export'].forEach(t=>{const el=$('tab-'+t); if(el) el.style.display=(btn.dataset.tab===t?'block':'none');});
 if(btn.dataset.tab==='export') refreshExport(); if(btn.dataset.tab==='aira') renderAiraAdmin(); if(btn.dataset.tab==='reviews') renderGoogleReviewsAdmin(); if(btn.dataset.tab==='blog' && window.RH_BLOG_ADMIN){window.RH_BLOG_ADMIN.refreshPosts();}
});

function loadSite(){
 $('promoTitle').value=site.promo.title||'';
 $('promoSubtitle').value=site.promo.subtitle||'';
 $('promoCta').value=site.promo.cta||'';
 $('promoHours').value=site.promo.hours||42;
 $('heroHeadline').value=site.hero.headline||'';
 $('heroSub').value=site.hero.subheadline||'';
 $('heroCta').value=site.hero.ctaPrimary||'';
 $('showcaseTitle').value=site.showcase.title||'';
 $('showcaseSubtitle').value=site.showcase.subtitle||'';
}
$('saveSite').onclick=()=>{
 site.promo.title=$('promoTitle').value; site.promo.subtitle=$('promoSubtitle').value; site.promo.cta=$('promoCta').value; site.promo.hours=Number($('promoHours').value||42);
 site.hero.headline=$('heroHeadline').value; site.hero.subheadline=$('heroSub').value; site.hero.ctaPrimary=$('heroCta').value;
 site.showcase.title=$('showcaseTitle').value; site.showcase.subtitle=$('showcaseSubtitle').value;
 localStorage.setItem('rh_site_content',JSON.stringify(site)); alert('Services page disimpan dalam browser admin.');
};
$('resetSite').onclick=()=>{site=structuredClone(DEFAULT_SITE);localStorage.setItem('rh_site_content',JSON.stringify(site));loadSite();};

function fillSelect(){
 if(!$('tplSelect')) return;
 $('tplSelect').innerHTML=Object.entries(templates).map(([k,v])=>`<option value="${k}">${v.industry} - ${v.name}</option>`).join('');
}
function loadTpl(){
 if(!$('tplSelect')) return;
 const k=$('tplSelect').value; const t=templates[k]; if(!t)return;
 $('tplColor').value=t.color||'#2563eb'; $('tplName').value=t.name||''; $('tplIndustry').value=t.industry||''; $('tplHeadline').value=t.headline||''; $('tplSub').value=t.subheadline||''; $('tplImage').value=t.image||''; $('tplServices').value=(t.services||[]).join('\n'); $('tplProducts').value=(t.products||[]).map(p=>`${p.title} | ${p.price} | ${p.desc}`).join('\n'); $('tplTestimonial').value=t.testimonial||''; $('tplCta').value=t.cta||'';
 $('imgPreview').style.backgroundImage=`url("${t.image}")`;
 if($('previewTpl')) $('previewTpl').removeAttribute('href');
}
if($('tplSelect')) $('tplSelect').onchange=loadTpl; if($('tplImage')) $('tplImage').oninput=()=>$('imgPreview').style.backgroundImage=`url("${$('tplImage').value}")`;
if($('saveTpl')) $('saveTpl').onclick=()=>{
 const k=$('tplSelect').value;
 templates[k]={...templates[k], color:$('tplColor').value, name:$('tplName').value, industry:$('tplIndustry').value, headline:$('tplHeadline').value, subheadline:$('tplSub').value, image:$('tplImage').value, services:$('tplServices').value.split('\n').map(x=>x.trim()).filter(Boolean), products:$('tplProducts').value.split('\n').map(line=>{const [title='',price='',desc='']=line.split('|').map(x=>x.trim());return {title,price,desc}}).filter(p=>p.title), testimonial:$('tplTestimonial').value, cta:$('tplCta').value};
 localStorage.setItem('rh_templates_data',JSON.stringify(templates)); loadTpl(); alert('Template disimpan dalam browser admin.');
};
if($('resetTpl')) $('resetTpl').onclick=()=>{const k=$('tplSelect').value; templates[k]=structuredClone(DEFAULT_TEMPLATES[k]); localStorage.setItem('rh_templates_data',JSON.stringify(templates));loadTpl();};

function refreshExport(){ $('exportSite').value=JSON.stringify(site,null,2); if($('airaQuestionExport')) $('airaQuestionExport').value=JSON.stringify(airaQuestions,null,2); if($('airaFaqExport')) $('airaFaqExport').value=JSON.stringify(airaFaq,null,2); }
$('refreshExport').onclick=refreshExport;
$('clearAll').onclick=()=>{if(confirm('Padam semua local changes?')){localStorage.removeItem('rh_site_content');localStorage.removeItem('rh_templates_data');localStorage.removeItem('rh_aira_question_bank');localStorage.removeItem('rh_aira_faq_bank');localStorage.removeItem('rh_google_reviews_bank');site=structuredClone(DEFAULT_SITE);templates=structuredClone(DEFAULT_TEMPLATES);airaQuestions=structuredClone(DEFAULT_AIRA_QUESTIONS);airaFaq=structuredClone(DEFAULT_AIRA_FAQ);googleReviews=(window.RH_GOOGLE_REVIEWS_SERVICE&&window.RH_GOOGLE_REVIEWS_SERVICE.defaults?window.RH_GOOGLE_REVIEWS_SERVICE.defaults():googleReviews);loadSite();fillSelect();loadTpl();renderAiraAdmin();renderGoogleReviewsAdmin();refreshExport();}};



function parseLines(v){return String(v||'').split('\n').map(x=>x.trim()).filter(Boolean)}
function escAdmin(s){return String(s||'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function parseConditions(text){const out={};parseLines(text).forEach(line=>{const idx=line.indexOf(':');if(idx<0)return;const key=line.slice(0,idx).trim();const values=line.slice(idx+1).split(',').map(x=>x.trim()).filter(Boolean);if(key&&values.length)out[key]=values;});return out;}
function formatConditions(obj){return Object.entries(obj||{}).map(([k,v])=>`${k}: ${(v||[]).join(', ')}`).join('\n')}
function setAiraStatus(msg,type='info'){const el=$('airaDataStatus');if(el){el.textContent=msg;el.style.borderColor=type==='ok'?'#bbf7d0':type==='warn'?'#fde68a':'#e2e8f0';el.style.background=type==='ok'?'#f0fdf4':type==='warn'?'#fffbeb':'#f8fafc';}}
function saveAiraStorage(){localStorage.setItem('rh_aira_question_bank',JSON.stringify(airaQuestions));localStorage.setItem('rh_aira_faq_bank',JSON.stringify(airaFaq));if(window.RH_AIRA_DATA_SERVICE){window.RH_AIRA_DATA_SERVICE.writeLocal(airaQuestions,airaFaq);}renderAiraPreview();refreshExport();setAiraStatus('Draft Aira disimpan dalam browser admin. Klik Publish ke Supabase untuk jadikan live semua device.','warn');}
async function loadAiraFromSource(){if(window.RH_AIRA_DATA_SERVICE){const res=await window.RH_AIRA_DATA_SERVICE.loadAll();airaQuestions=res.questionBank||airaQuestions;airaFaq=res.faqBank||airaFaq;setAiraStatus(res.source==='supabase'?'Aira data sedang digunakan dari Supabase.':'Supabase tidak aktif/kosong. Aira guna localStorage fallback. '+(res.warning||''),res.source==='supabase'?'ok':'warn');}renderAiraAdmin();}
async function publishAiraToSupabase(){if(!window.RH_AIRA_DATA_SERVICE){setAiraStatus('Aira Data Service tidak dimuatkan.','warn');return;}const res=await window.RH_AIRA_DATA_SERVICE.publishAll(airaQuestions,airaFaq);if(res.ok){setAiraStatus('Berjaya publish ke Supabase. Website akan baca bank soalan live tanpa clear cache.','ok');alert('Aira Question Bank / FAQ / Packages berjaya publish ke Supabase.');}else{setAiraStatus('Gagal publish ke Supabase: '+res.error,'warn');alert('Gagal publish ke Supabase. Draft masih disimpan local. Error: '+res.error);}}
function renderAiraAdmin(){ if(!$('airaQuestionList'))return; renderAiraQuestions(); renderAiraFaq(); renderAiraPackages(); renderAiraPreview(); refreshExport(); }
function switchAiraSub(name){['questions','faq','packages','export'].forEach(n=>{const el=$('aira'+n.charAt(0).toUpperCase()+n.slice(1)+'Panel');if(el)el.style.display=n===name?'block':'none';});document.querySelectorAll('[data-aira-sub]').forEach(b=>b.classList.toggle('active',b.dataset.airaSub===name));renderAiraPreview();}
document.querySelectorAll('[data-aira-sub]').forEach(btn=>btn.onclick=()=>switchAiraSub(btn.dataset.airaSub));
function renderAiraQuestions(){const list=$('airaQuestionList');if(!list)return;list.innerHTML=(airaQuestions.steps||[]).map((q,i)=>`<div class="aira-card"><div class="aira-card-head"><div><span class="pill-muted">#${i+1} ${escAdmin(q.type|| (q.input?'input':'choice'))}</span><h3>${escAdmin(q.question)}</h3><p><code>${escAdmin(q.key)}</code>${q.conditional?' • conditional':''}</p></div></div><div class="mini-actions"><button class="dark" onclick="editAiraQuestion(${i})">Edit</button><button onclick="moveAiraQuestion(${i},-1)">↑</button><button onclick="moveAiraQuestion(${i},1)">↓</button><button onclick="duplicateAiraQuestionAt(${i})">Duplicate</button></div></div>`).join('');if(!$('airaQuestionIndex').value && airaQuestions.steps&&airaQuestions.steps.length) editAiraQuestion(0);}
window.editAiraQuestion=function(i){const q=airaQuestions.steps[i];if(!q)return;$('airaQuestionIndex').value=i;$('airaQuestionEditorTitle').textContent='Edit Soalan #'+(i+1);$('airaQKey').value=q.key||'';$('airaQType').value=(q.input||q.type==='input')?'input':'choice';$('airaQText').value=q.question||'';$('airaQOptions').value=(q.options||[]).join('\n');$('airaQPlaceholder').value=q.placeholder||'';$('airaQValidation').value=q.validation||'';$('airaQConditional').checked=!!q.conditional;$('airaQConditions').value=formatConditions(q.conditions||{});};
window.moveAiraQuestion=function(i,dir){const arr=airaQuestions.steps||[];const j=i+dir;if(j<0||j>=arr.length)return;[arr[i],arr[j]]=[arr[j],arr[i]];saveAiraStorage();renderAiraQuestions();editAiraQuestion(j);};
window.duplicateAiraQuestionAt=function(i){const q=structuredClone(airaQuestions.steps[i]);q.key=(q.key||'question')+'_copy';airaQuestions.steps.splice(i+1,0,q);saveAiraStorage();renderAiraQuestions();editAiraQuestion(i+1);};
$('addAiraQuestion')&&($('addAiraQuestion').onclick=()=>{airaQuestions.steps.push({key:'new_question_'+Date.now(),question:'Soalan baharu',type:'choice',options:['Pilihan 1','Pilihan 2']});saveAiraStorage();renderAiraQuestions();editAiraQuestion(airaQuestions.steps.length-1);});
$('saveAiraQuestion')&&($('saveAiraQuestion').onclick=()=>{const i=Number($('airaQuestionIndex').value||0);const type=$('airaQType').value;const q={key:$('airaQKey').value.trim()||('question_'+Date.now()),question:$('airaQText').value.trim(),type,input:type==='input',placeholder:$('airaQPlaceholder').value.trim(),validation:$('airaQValidation').value,options:parseLines($('airaQOptions').value)};q.required=true;if($('airaQConditional').checked){q.conditional=true;q.conditions=parseConditions($('airaQConditions').value)}airaQuestions.steps[i]=q;saveAiraStorage();renderAiraQuestions();editAiraQuestion(i);alert('Soalan Aira disimpan.');});
$('duplicateAiraQuestion')&&($('duplicateAiraQuestion').onclick=()=>duplicateAiraQuestionAt(Number($('airaQuestionIndex').value||0)));
$('deleteAiraQuestion')&&($('deleteAiraQuestion').onclick=()=>{const i=Number($('airaQuestionIndex').value||0);if(confirm('Delete soalan ini?')){airaQuestions.steps.splice(i,1);saveAiraStorage();$('airaQuestionIndex').value='';renderAiraQuestions();}});
$('resetAiraQuestion')&&($('resetAiraQuestion').onclick=()=>{if(confirm('Reset question bank kepada default?')){airaQuestions=structuredClone(DEFAULT_AIRA_QUESTIONS);saveAiraStorage();renderAiraQuestions();}});
function renderAiraFaq(){const list=$('airaFaqList');if(!list)return;list.innerHTML=(airaFaq.faq||[]).map((f,i)=>`<div class="aira-card"><div class="aira-card-head"><div><span class="pill-muted">${escAdmin(f.topic)}</span><h3>${escAdmin((f.triggers||[]).slice(0,4).join(', '))}</h3><p>${escAdmin(String(f.answer||'').replace(/<[^>]+>/g,'')).slice(0,120)}...</p></div></div><div class="mini-actions"><button class="dark" onclick="editAiraFaq(${i})">Edit</button></div></div>`).join('');if(!$('airaFaqIndex').value && airaFaq.faq&&airaFaq.faq.length) editAiraFaq(0);}
window.editAiraFaq=function(i){const f=airaFaq.faq[i];if(!f)return;$('airaFaqIndex').value=i;$('airaFaqEditorTitle').textContent='Edit FAQ: '+(f.topic||'');$('airaFaqTopic').value=f.topic||'';$('airaFaqTriggers').value=(f.triggers||[]).join(', ');$('airaFaqAnswer').value=f.answer||'';};
$('addAiraFaq')&&($('addAiraFaq').onclick=()=>{airaFaq.faq.push({topic:'topik_baru',triggers:['trigger'],answer:'Jawapan baharu.'});saveAiraStorage();renderAiraFaq();editAiraFaq(airaFaq.faq.length-1);});
$('saveAiraFaq')&&($('saveAiraFaq').onclick=()=>{const i=Number($('airaFaqIndex').value||0);airaFaq.faq[i]={topic:$('airaFaqTopic').value.trim(),triggers:$('airaFaqTriggers').value.split(',').map(x=>x.trim()).filter(Boolean),answer:$('airaFaqAnswer').value.trim()};saveAiraStorage();renderAiraFaq();editAiraFaq(i);alert('FAQ Aira disimpan.');});
$('deleteAiraFaq')&&($('deleteAiraFaq').onclick=()=>{const i=Number($('airaFaqIndex').value||0);if(confirm('Delete FAQ ini?')){airaFaq.faq.splice(i,1);saveAiraStorage();$('airaFaqIndex').value='';renderAiraFaq();}});
$('resetAiraFaq')&&($('resetAiraFaq').onclick=()=>{if(confirm('Reset FAQ kepada default?')){airaFaq=structuredClone(DEFAULT_AIRA_FAQ);saveAiraStorage();renderAiraFaq();}});
function renderAiraPackages(){const list=$('airaPackageList');if(!list)return;const pkgs=airaQuestions.packages||{};list.innerHTML=Object.entries(pkgs).map(([k,v])=>`<div class="aira-card"><span class="pill-muted">${escAdmin(v.price||'')}</span><h3>${escAdmin(k)}</h3><p>${escAdmin((v.features||[]).slice(0,3).join(' • '))}</p><div class="mini-actions"><button class="dark" onclick="editAiraPackage('${escAdmin(k)}')">Edit</button></div></div>`).join('');const first=Object.keys(pkgs)[0];if(first&&!$('airaPackageKey').value) editAiraPackage(first);}
window.editAiraPackage=function(k){const v=(airaQuestions.packages||{})[k];if(!v)return;$('airaPackageKey').value=k;$('airaPkgName').value=k;$('airaPkgPrice').value=v.price||'';$('airaPkgBestFor').value=(v.bestFor||[]).join('\n');$('airaPkgFeatures').value=(v.features||[]).join('\n');};
$('saveAiraPackage')&&($('saveAiraPackage').onclick=()=>{const old=$('airaPackageKey').value;const name=$('airaPkgName').value.trim()||old||'Package Baru';airaQuestions.packages=airaQuestions.packages||{};if(old&&old!==name)delete airaQuestions.packages[old];airaQuestions.packages[name]={price:$('airaPkgPrice').value.trim(),bestFor:parseLines($('airaPkgBestFor').value),features:parseLines($('airaPkgFeatures').value)};saveAiraStorage();renderAiraPackages();editAiraPackage(name);alert('Package disimpan.');});
